import os

def delete_file(filename):
    """
    Deletes a user's uploaded file from the 'uploads' directory.

    Args:
        filename: The filename of the file to delete.

    Raises:
        ValueError: If the filename contains directory traversal characters.
    """

    # Validate filename
    if '..' in filename or '/' in filename:
        raise ValueError('Directory traversal attack detected.')

    # Delete the file
    os.remove(os.path.join('uploads', filename))